from flask import Flask, request, jsonify
from flask_jwt_extended import (
    JWTManager, create_access_token, jwt_required, get_jwt_identity
)
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'super-secret-change-me'
jwt = JWTManager(app)

users = {}   # {id: {username, password_hash}}
_next_id = 1


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username', '').strip()
    password = data.get('password', '')
    if not username or not password:
        return jsonify({'error': 'username and password required'}), 400
    if any(u['username'] == username for u in users.values()):
        return jsonify({'error': 'Username already taken'}), 409

    global _next_id
    uid = _next_id
    _next_id += 1
    users[uid] = {'username': username,
                  'password_hash': generate_password_hash(password)}
    return jsonify({'message': 'User registered', 'id': uid}), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username', '')
    password = data.get('password', '')
    user = next((u for u in users.values() if u['username'] == username), None)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    token = create_access_token(identity=username)
    return jsonify({'token': token}), 200


@app.route('/profile', methods=['GET'])
@jwt_required()
def profile():
    current_user = get_jwt_identity()
    uid, user = next(
        ((uid, u) for uid, u in users.items() if u['username'] == current_user),
        (None, None)
    )
    if not user:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'id': uid, 'username': user['username']}), 200


if __name__ == '__main__':
    app.run(debug=True)
